// scanner.js
async function findSessionById(id) {
  var cached = shared.sessionCache.get(id);
  if (cached && cached._file) return cached;
  var all = await scanSessions(shared.PROJECTS_DIR, []);
  return all.find(s => s.id === id) || null;
}

